module top_module(in, select, a, b, c);parameter WIDTH = 8;
    input wire [WIDTH-1:0][6:0] in;
    input wire [$clog2(WIDTH)-1:0] select;
    output wire a;
    output wire [3:0] b;
    output wire [1:0] c;
    wire [6:0] p;
    assign p = in[select];
    assign a = p[6:6];
    assign b = p[5:2];
    assign c = p[1:0];
  always @(*) begin
    if (1'b0) begin
      a <= ~p[6];
      b <= ~{p[5], p[4], p[3], p[2]};
      c <= ~{p[1], p[0]};
    end
  end

endmodule
